import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { HackathonService } from '../../../../core/services/hackathon.service';
import { CreaHackathonRequest } from '../../../../core/models/hackathon.model';

@Component({
  selector: 'app-create-hackathon',
  templateUrl: './create-hackathon.component.html',
  styleUrls: ['./create-hackathon.component.scss']
})
export class CreateHackathonComponent implements OnInit {
  hackathonForm: FormGroup;
  isSubmitting = false;
  errorMessage = '';

  constructor(
    private fb: FormBuilder,
    private hackathonService: HackathonService,
    private router: Router
  ) {
    this.hackathonForm = this.fb.group({
      nome: ['', [Validators.required, Validators.minLength(3)]],
      regolamento: ['', [Validators.required]],
      dataInizio: ['', Validators.required],
      dataFine: ['', Validators.required],
      luogo: [''],
      premioInDenaro: [0, [Validators.required, Validators.min(0)]]
    });
  }

  ngOnInit(): void {}

  onSubmit(): void {
    if (this.hackathonForm.valid) {
      this.isSubmitting = true;
      this.errorMessage = '';

      const request: CreaHackathonRequest = this.hackathonForm.value;

      this.hackathonService.creaHackathon(request).subscribe({
        next: () => {
          this.isSubmitting = false;
          this.router.navigate(['/hackathons']);
        },
        error: (err) => {
          this.isSubmitting = false;
          this.errorMessage = err.error?.message || 'Error occurred while creating the hackathon. Please try again.';
        }
      });
    } else {
      Object.keys(this.hackathonForm.controls).forEach(key => {
        this.hackathonForm.get(key)?.markAsTouched();
      });
    }
  }

  onCancel(): void {
    this.router.navigate(['/hackathons']);
  }
}
<div class="create-hackathon-container fade-in">
  <div class="header">
    <button class="back-btn" (click)="onCancel()">
      <span>←</span> Back to Hackathons
    </button>
    <h1>Create New Hackathon 🚀</h1>
    <p class="subtitle">Set up your next great coding competition</p>
  </div>

  <div class="form-card">
    <div class="error-alert" *ngIf="errorMessage">
      {{ errorMessage }}
    </div>

    <form [formGroup]="hackathonForm" (ngSubmit)="onSubmit()">

      <div class="form-group">
        <label for="nome">Hackathon Name <span class="required">*</span></label>
        <input id="nome" type="text" formControlName="nome" class="form-control" placeholder="E.g. Summer Coding Challenge">
        <div class="error-text" *ngIf="hackathonForm.get('nome')?.touched && hackathonForm.get('nome')?.invalid">
          Please provide a valid name (min 3 characters).
        </div>
      </div>

      <div class="form-row">
        <div class="form-group half-width">
          <label for="dataInizio">Start Date <span class="required">*</span></label>
          <input id="dataInizio" type="datetime-local" formControlName="dataInizio" class="form-control">
          <div class="error-text" *ngIf="hackathonForm.get('dataInizio')?.touched && hackathonForm.get('dataInizio')?.invalid">
            Start date is required.
          </div>
        </div>

        <div class="form-group half-width">
          <label for="dataFine">End Date <span class="required">*</span></label>
          <input id="dataFine" type="datetime-local" formControlName="dataFine" class="form-control">
          <div class="error-text" *ngIf="hackathonForm.get('dataFine')?.touched && hackathonForm.get('dataFine')?.invalid">
            End date is required.
          </div>
        </div>
      </div>

      <div class="form-row">
        <div class="form-group half-width">
          <label for="luogo">Location (Optional)</label>
          <input id="luogo" type="text" formControlName="luogo" class="form-control" placeholder="E.g. On-site or Online">
        </div>

        <div class="form-group half-width">
          <label for="premioInDenaro">Prize Money ($) <span class="required">*</span></label>
          <input id="premioInDenaro" type="number" formControlName="premioInDenaro" class="form-control" min="0">
          <div class="error-text" *ngIf="hackathonForm.get('premioInDenaro')?.touched && hackathonForm.get('premioInDenaro')?.invalid">
            Please provide a valid prize amount.
          </div>
        </div>
      </div>

      <div class="form-group">
        <label for="regolamento">Rules and Description <span class="required">*</span></label>
        <textarea id="regolamento" formControlName="regolamento" class="form-control" rows="5" placeholder="Describe the rules, objectives, and any necessary information for participants..."></textarea>
        <div class="error-text" *ngIf="hackathonForm.get('regolamento')?.touched && hackathonForm.get('regolamento')?.invalid">
          Rules and description are required.
        </div>
      </div>

      <div class="form-actions">
        <button type="button" class="btn-secondary" (click)="onCancel()" [disabled]="isSubmitting">Cancel</button>
        <button type="submit" class="btn-primary" [disabled]="hackathonForm.invalid || isSubmitting">
          <span *ngIf="isSubmitting" class="spinner"></span>
          <span *ngIf="!isSubmitting">Create Hackathon</span>
          <span *ngIf="isSubmitting">Creating...</span>
        </button>
      </div>
    </form>
  </div>
</div>
